import pytest

def title_case(s: str) -> str:
    return ' '.join(word.capitalize() for word in s.split())

class TestTitleCase:

    def test_happy_path(self):
        assert title_case("this is a string") == "This Is A String"
        assert title_case("aBcDeFg") == "Abcdefg"
        assert title_case("multiple   spaces") == "Multiple Spaces"

    def test_empty_string(self):
        assert title_case("") == ""

    def test_string_with_only_spaces(self):
        assert title_case("   ") == ""

    def test_string_with_leading_and_trailing_spaces(self):
        assert title_case("  leading and trailing  ") == "Leading And Trailing"

    def test_string_with_numbers(self):
        assert title_case("123 abc") == "123 Abc"
        assert title_case("abc 123") == "Abc 123"
        assert title_case("123") == "123"

    def test_string_with_special_characters(self):
        assert title_case("!@#$%^&*()") == "!@#$%^&*()"
        assert title_case("abc!@#") == "Abc!@#"
        assert title_case("!@# abc") == "!@# Abc"

    def test_string_with_mixed_case_and_special_characters(self):
        assert title_case("aBc!@#DeF") == "Abc!@#def"

    def test_string_with_unicode_characters(self):
        assert title_case("你好世界") == "你好世界"
        assert title_case("你好 世界") == "你好 世界"
        assert title_case("héllö wørld") == "Héllö Wørld"

    def test_string_with_hyphens(self):
        assert title_case("self-assessment") == "Self-assessment"
        assert title_case("self - assessment") == "Self - Assessment"

    def test_string_with_apostrophes(self):
        assert title_case("it's a test") == "It's A Test"
        assert title_case("o'malley") == "O'malley"
